fn solve(c: i64, connections: Vec<Vec<i64>>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    // Build the graph
    let mut graph: HashMap<i64, HashSet<i64>> = HashMap::new();
    for conn in &connections {
        let u = conn[0];
        let v = conn[1];
        graph.entry(u).or_insert_with(HashSet::new).insert(v);
        graph.entry(v).or_insert_with(HashSet::new).insert(u);
    }

    // For each node, keep track of its current parent in the DSU
    let mut parent: HashMap<i64, i64> = HashMap::new();
    // For each node, keep track of the minimum id in its set
    let mut min_id: HashMap<i64, i64> = HashMap::new();
    // Track which nodes are online
    let mut online: HashSet<i64> = HashSet::new();
    // Initialize DSU
    for i in 1..=c {
        parent.insert(i, i);
        min_id.insert(i, i);
        online.insert(i);
    }

    // Function to find the root of a node
    fn find(parent: &mut HashMap<i64, i64>, x: i64) -> i64 {
        if parent[&x] != x {
            parent[&x] = find(parent, parent[&x]);
        }
        parent[&x]
    }

    // Function to union two sets
    fn union(parent: &mut HashMap<i64, i64>, min_id: &mut HashMap<i64, i64>, x: i64, y: i64) {
        let root_x = find(parent, x);
        let root_y = find(parent, y);
        if root_x != root_y {
            // Make root_x the parent of root_y
            parent.insert(root_y, root_x);
            // Update the min_id of root_x
            min_id.insert(root_x, std::cmp::min(min_id[&root_x], min_id[&root_y]));
        }
    }

    // Process queries
    let mut result = Vec::new();
    for query in &queries {
        if query[0] == 1 {
            let x = query[1];
            if online.contains(&x) {
                // The node is online, so it handles the check
                result.push(x);
            } else {
                // Find the root of x
                let root = find(&parent, x);
                // Check if there are any online nodes in the same set
                let min_online = min_id.get(&root).copied();
                if let Some(min) = min_online {
                    if online.contains(&min) {
                        result.push(min);
                    } else {
                        result.push(-1);
                    }
                } else {
                    result.push(-1);
                }
            }
        } else {
            let x = query[1];
            if online.contains(&x) {
                online.remove(&x);
            }
        }
    }

    result
